"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import {
    Megaphone,
    Plus,
    Trash2,
    Users,
    GraduationCap,
    Globe,
    Bell,
    Clock
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { MOCK_ANNOUNCEMENTS } from "@/lib/utils";
import { Announcement } from "@/lib/types";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import { Label } from "@/components/ui/label";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { toast } from "sonner";
import { cn } from "@/lib/utils";

export default function AnnouncementsPage() {
    const [announcements, setAnnouncements] = useState<Announcement[]>(MOCK_ANNOUNCEMENTS);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [newAnnouncement, setNewAnnouncement] = useState<Partial<Announcement>>({
        title: "",
        content: "",
        targetAudience: "ALL",
        priority: "MEDIUM"
    });

    const handleCreate = (e: React.FormEvent) => {
        e.preventDefault();
        const announcement: Announcement = {
            id: Date.now().toString(),
            title: newAnnouncement.title!,
            content: newAnnouncement.content!,
            targetAudience: newAnnouncement.targetAudience as any,
            priority: newAnnouncement.priority as any,
            date: new Date().toISOString().split('T')[0],
            author: "Admin"
        };

        setAnnouncements([announcement, ...announcements]);
        setIsDialogOpen(false);
        setNewAnnouncement({ title: "", content: "", targetAudience: "ALL", priority: "MEDIUM" });
        toast.success("Announcement Posted Successfully");
    };

    const getPriorityColor = (priority: string) => {
        switch (priority) {
            case 'HIGH': return 'bg-rose-100 text-rose-700 dark:bg-rose-900/40 dark:text-rose-400';
            case 'MEDIUM': return 'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-400';
            case 'LOW': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-400';
            default: return 'bg-slate-100 text-slate-700';
        }
    };

    const getAudienceIcon = (audience: string) => {
        switch (audience) {
            case 'STUDENT': return <Users className="h-4 w-4 mr-1" />;
            case 'FACULTY': return <GraduationCap className="h-4 w-4 mr-1" />;
            default: return <Globe className="h-4 w-4 mr-1" />;
        }
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-3xl font-bold tracking-tight">Announcements</h2>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button>
                            <Plus className="mr-2 h-4 w-4" /> Create Notice
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-lg">
                        <DialogHeader>
                            <DialogTitle>Post New Announcement</DialogTitle>
                            <DialogDescription>Create a notice for students or faculty.</DialogDescription>
                        </DialogHeader>
                        <form onSubmit={handleCreate} className="space-y-4">
                            <div className="space-y-2">
                                <Label>Title</Label>
                                <Input
                                    value={newAnnouncement.title}
                                    onChange={(e) => setNewAnnouncement({ ...newAnnouncement, title: e.target.value })}
                                    required
                                    placeholder="e.g. Exam Schedule Release"
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Content</Label>
                                <Textarea
                                    value={newAnnouncement.content}
                                    onChange={(e) => setNewAnnouncement({ ...newAnnouncement, content: e.target.value })}
                                    required
                                    placeholder="Enter detailed information..."
                                    rows={4}
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label>Target Audience</Label>
                                    <Select
                                        value={newAnnouncement.targetAudience}
                                        onValueChange={(val) => setNewAnnouncement({ ...newAnnouncement, targetAudience: val as any })}
                                    >
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="ALL">Everyone</SelectItem>
                                            <SelectItem value="STUDENT">Students Only</SelectItem>
                                            <SelectItem value="FACULTY">Faculty Only</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <Label>Priority</Label>
                                    <Select
                                        value={newAnnouncement.priority}
                                        onValueChange={(val) => setNewAnnouncement({ ...newAnnouncement, priority: val as any })}
                                    >
                                        <SelectTrigger>
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="HIGH">High Priority</SelectItem>
                                            <SelectItem value="MEDIUM">Medium</SelectItem>
                                            <SelectItem value="LOW">Low</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                            <Button type="submit" className="w-full">Publish Notice</Button>
                        </form>
                    </DialogContent>
                </Dialog>
            </div>

            <div className="grid gap-6">
                {announcements.map((announcement) => (
                    <Card key={announcement.id} className="relative overflow-hidden transition-shadow hover:shadow-md">
                        <div className={cn("absolute left-0 top-0 bottom-0 w-1",
                            announcement.priority === 'HIGH' ? 'bg-rose-500' :
                                announcement.priority === 'MEDIUM' ? 'bg-amber-500' : 'bg-blue-500'
                        )} />
                        <CardHeader className="pb-2">
                            <div className="flex justify-between items-start">
                                <div className="space-y-1">
                                    <div className="flex items-center gap-2">
                                        <span className={cn("text-[10px] font-bold px-2 py-0.5 rounded-full uppercase tracking-wider", getPriorityColor(announcement.priority))}>
                                            {announcement.priority}
                                        </span>
                                        <span className="text-xs text-muted-foreground flex items-center">
                                            <Clock className="h-3 w-3 mr-1" />
                                            {announcement.date}
                                        </span>
                                    </div>
                                    <CardTitle className="text-xl">{announcement.title}</CardTitle>
                                </div>
                                <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-red-500">
                                    <Trash2 className="h-4 w-4" />
                                </Button>
                            </div>
                        </CardHeader>
                        <CardContent>
                            <p className="text-muted-foreground text-sm leading-relaxed">
                                {announcement.content}
                            </p>
                        </CardContent>
                        <CardFooter className="bg-muted/50 py-2 px-6 flex justify-between items-center">
                            <div className="flex items-center text-xs text-muted-foreground">
                                <span className="font-medium mr-1">To:</span>
                                <span className="flex items-center bg-background border px-2 py-0.5 rounded shadow-sm">
                                    {getAudienceIcon(announcement.targetAudience)}
                                    {announcement.targetAudience}
                                </span>
                            </div>
                            <div className="text-xs text-muted-foreground italic">
                                Posted by {announcement.author}
                            </div>
                        </CardFooter>
                    </Card>
                ))}
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import {
    Calendar,
    Plus,
    FileText,
    Send,
    MoreHorizontal,
    Trash2,
    Pencil
} from "lucide-react";
import { MOCK_STUDENTS } from "@/lib/utils";
import { Badge } from "@/components/ui/badge";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Input } from "@/components/ui/input";
import {
    DropdownMenu,
    DropdownMenuContent,
    DropdownMenuItem,
    DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { toast } from "sonner";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";

const MOCK_EXAMS = [
    { id: 1, name: "Mid Semester Exam", course: "B.Tech CSE", date: "2024-03-15", status: "Completed" },
    { id: 2, name: "End Semester Exam", course: "B.Tech CSE", date: "2024-05-20", status: "Scheduled" },
    { id: 3, name: "Practical Lab Exam", course: "B.Tech ECE", date: "2024-04-10", status: "Scheduled" },
];

export default function ExamsPage() {
    const [marksGiven, setMarksGiven] = useState<Record<string, number>>({});

    const handleMarkChange = (studentId: string, mark: number) => {
        setMarksGiven(prev => ({ ...prev, [studentId]: mark }));
    };

    const calculateGrade = (mark: number) => {
        if (mark >= 90) return "O";
        if (mark >= 80) return "A+";
        if (mark >= 70) return "A";
        if (mark >= 60) return "B+";
        if (mark >= 50) return "B";
        return "F";
    };

    const publishResults = () => {
        toast.success("Results Published Successfully", {
            description: "Students can now view their results in the portal."
        });
    };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between">
                <h2 className="text-3xl font-bold tracking-tight">Examinations</h2>
                <Button>
                    <Plus className="mr-2 h-4 w-4" /> Schedule Exam
                </Button>
            </div>

            <Tabs defaultValue="schedule" className="w-full">
                <TabsList>
                    <TabsTrigger value="schedule">Exam Schedule</TabsTrigger>
                    <TabsTrigger value="results">Results & Marks</TabsTrigger>
                </TabsList>

                <TabsContent value="schedule">
                    <Card>
                        <CardHeader>
                            <CardTitle>Upcoming & Past Exams</CardTitle>
                            <CardDescription>Manage examination schedules.</CardDescription>
                        </CardHeader>
                        <CardContent>
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Exam Name</TableHead>
                                        <TableHead>Course</TableHead>
                                        <TableHead>Date</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {MOCK_EXAMS.map((exam) => (
                                        <TableRow key={exam.id}>
                                            <TableCell className="font-medium">{exam.name}</TableCell>
                                            <TableCell>{exam.course}</TableCell>
                                            <TableCell>{exam.date}</TableCell>
                                            <TableCell>
                                                <Badge variant={exam.status === "Completed" ? "secondary" : "default"}>
                                                    {exam.status}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <DropdownMenu>
                                                    <DropdownMenuTrigger asChild>
                                                        <Button variant="ghost" className="h-8 w-8 p-0">
                                                            <MoreHorizontal className="h-4 w-4" />
                                                        </Button>
                                                    </DropdownMenuTrigger>
                                                    <DropdownMenuContent align="end">
                                                        <DropdownMenuItem><Pencil className="mr-2 h-4 w-4" /> Edit</DropdownMenuItem>
                                                        <DropdownMenuItem className="text-red-600"><Trash2 className="mr-2 h-4 w-4" /> Delete</DropdownMenuItem>
                                                    </DropdownMenuContent>
                                                </DropdownMenu>
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="results" className="space-y-6">
                    <Card>
                        <CardHeader>
                            <div className="flex justify-between items-center">
                                <div>
                                    <CardTitle>Enter Marks</CardTitle>
                                    <CardDescription>Enter marks for Mid Semester Exam - B.Tech CSE</CardDescription>
                                </div>
                                <div className="flex items-center space-x-2">
                                    <Switch id="publish-mode" />
                                    <Label htmlFor="publish-mode">Publish Immediately</Label>
                                </div>
                            </div>
                        </CardHeader>
                        <CardContent>
                            <div className="rounded-md border">
                                <Table>
                                    <TableHeader>
                                        <TableRow>
                                            <TableHead className="w-[100px]">Roll No</TableHead>
                                            <TableHead>Student Name</TableHead>
                                            <TableHead>Marks (Out of 100)</TableHead>
                                            <TableHead>Grade</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {MOCK_STUDENTS.slice(0, 8).map((student) => (
                                            <TableRow key={student.id}>
                                                <TableCell className="font-mono">{student.rollNumber}</TableCell>
                                                <TableCell>{student.name}</TableCell>
                                                <TableCell>
                                                    <Input
                                                        type="number"
                                                        max={100}
                                                        min={0}
                                                        className="w-24"
                                                        placeholder="0"
                                                        onChange={(e) => handleMarkChange(student.id, Number(e.target.value))}
                                                    />
                                                </TableCell>
                                                <TableCell>
                                                    {marksGiven[student.id] ? (
                                                        <Badge variant="outline" className="font-bold">
                                                            {calculateGrade(marksGiven[student.id])}
                                                        </Badge>
                                                    ) : (
                                                        <span className="text-muted-foreground">-</span>
                                                    )}
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            </div>
                        </CardContent>
                        <CardContent className="border-t pt-6 bg-muted/10 flex justify-end">
                            <Button onClick={publishResults}>
                                <Send className="mr-2 h-4 w-4" /> Publish Results
                            </Button>
                        </CardContent>
                    </Card>
                </TabsContent>
            </Tabs>
        </div>
    );
}

